VALUES
  ('optometrist-moex-00334', 'optometrist', 'optometrist-moex-113-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關視覺對比敏感度（contrastsensitivityfunction,CSF）檢查，下列何者錯誤？', '["在視力還是正常時，可以較早評估視覺系統的損害情況", "檢測人的視覺系統對明暗不同的條柵圖的識別能力", "檢查時患者不須戴上視力矯正眼鏡", "在視覺發育研究、眼疾病的早期診斷和病情追蹤上有著重要的作用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "87d2d58d5233", "answer_pdf_sha1": "d9cba2739812", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00335', 'optometrist', 'optometrist-moex-113-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關視網膜電流圖（electro-retinogram,ERG）之敘述，下列何者錯誤？', '["視網膜受到光刺激後，從感光細胞到雙極細胞（bipolarcells），無長突細胞（amacrinecells），會產 生一系列的電反應", "正常視網膜電流圖有賴於視網膜色素上皮層、感光細胞、外網狀層（outerplexiformlayer）、雙極細 胞、水平細胞、無長突細胞、穆氏細胞（Müllercell）及視網膜脈絡膜血液循環等的正常功能", "侷限於黃斑部的病變，因為視網膜電流圖Full-Field（Ganzfeld）ERG非常精準，也會出現異常反應", "視網膜電流圖主要是反映外視網膜的健康狀態"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "87d2d58d5233", "answer_pdf_sha1": "d9cba2739812", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00336', 'optometrist', 'optometrist-moex-113-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '關於第四對腦神經的特性，下列敘述何者錯誤？', '["是唯一由腦背部（dorsalside）發出的神經", "也會產生交叉、支配神經核對側的上斜肌（superiorobliquemuscle）", "路徑長，因而脆弱易受傷", "在所有腦神經中，含有最多軸索（axon）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "87d2d58d5233", "answer_pdf_sha1": "d9cba2739812", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00337', 'optometrist', 'optometrist-moex-113-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '下列那一條神經並無穿過肌腱總環（commontendinousring）？', '["鼻睫神經（nasociliarynerve）", "動眼神經", "滑車神經", "外旋神經"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "87d2d58d5233", "answer_pdf_sha1": "d9cba2739812", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00338', 'optometrist', 'optometrist-moex-113-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '關於視動震顫（optokineticnystagmus）的敘述，下列何者錯誤？', '["屬於正常的眼生理震顫", "在嬰兒時期，視動震顫為評估視覺發育的方式之一", "當一連續物體在眼前向右移動，眼球會向右慢速運動，再向左側快速運動", "視動震顫屬於雙眼對稱型水平震顫"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "87d2d58d5233", "answer_pdf_sha1": "d9cba2739812", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00339', 'optometrist', 'optometrist-moex-113-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關瞳孔大小影響視覺表現之敘述，下列何者錯誤？', '["瞳孔愈小，視物的景深增加；當小於2mm時，繞射現象會提升視力的品質", "瞳孔愈大而直徑超過6mm時，球面像差（sphericalaberration）較易顯現", "看近物時，瞳孔縮小、調節作用增加及雙眼內聚，稱為近反射（nearreflex）", "通過瞳孔中心而進入眼睛的光線刺激視網膜錐狀細胞的數目遠超過光線斜向照射的錐狀細胞，因此 有較好的視覺表現"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "87d2d58d5233", "answer_pdf_sha1": "d9cba2739812", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00340', 'optometrist', 'optometrist-moex-113-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關色覺的敘述，下列何者錯誤？', '["相對於物體的移動是由較大且傳遞較快的 Magno 神經節細胞來負責，色覺則是由較小且傳遞較慢 的Parvo神經節細胞來負責", "紅綠色覺是由開（ON）與關（OFF）兩種雙極細胞來傳遞，而藍色覺則只由開（ON）雙極細胞來 傳遞", "吸收短波長的S視蛋白位於第七對染色體，其異常所造成的黃藍色覺缺損較為罕見", "紅綠色覺異常是最常見的色覺異常，而其中又以吸收長波長的L視蛋白之基因表現異常最常見"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "87d2d58d5233", "answer_pdf_sha1": "d9cba2739812", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00341', 'optometrist', 'optometrist-moex-113-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '各級驗光師公會之章程應載明事項，不包括下列何者？', '["名稱、區域及會所所在地", "會員之入會或出會", "理事、監事名額、權限、任期及其選任、解任", "執業收費準則"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "87d2d58d5233", "answer_pdf_sha1": "d9cba2739812", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00342', 'optometrist', 'optometrist-moex-113-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '驗光師與驗光生的業務範圍，下列敘述何者正確？', '["驗光師可以對六歲以上十五歲以下者第一次驗光及配鏡，驗光生不可以", "驗光師可以為一般隱形眼鏡配鏡所為之驗光，驗光生不可以", "驗光師可以為低視力者輔助器具之教導使用，驗光生不可以", "兩者規定的業務範圍都相同"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "87d2d58d5233", "answer_pdf_sha1": "d9cba2739812", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-00343', 'optometrist', 'optometrist-moex-113-b0a2f330', 'sub-optometrist-02', NULL, 'single_choice', '有關開業執照之規定，下列敘述何者正確？①驗光所應將其開業執照及收費標準，揭示於明顯處  ②', '["驗光 所容留未具驗光人員資格之人員，擅自執行驗光人員業務者，廢止其開業執照", "驗光所登記事項如 有變更，應於事實發生之日起三十日內，報請原發開業執照機關備查  ⑤驗光所之負責驗光人員因故 不能執行業務指定合於規定資格者代理時，代理期間超過四十五日者，應由被代理者報請原發開業執 照機關備查  ⑥驗光所之開業執照不慎遺失時，應填具申請書並繳納開業執照費後，向中央主管機關 申請補發", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:40+00:00", "source_pdf_sha1": "87d2d58d5233", "answer_pdf_sha1": "d9cba2739812", "source_family": "moex-gov-tw", "moex": {"exam_code": "113100", "c": "109", "s": "0901", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球解剖生理學與倫理法規", "year": "113", "exam_name": "113年第二次專技人員高等考試營養師、護理師、社會工作師考試、113年專技人員高等考試心理師、法醫師、語言治療師、聽力師、牙體技術師、公共衛...", "original_question_number": 38, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
